from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about a monument (or related entity) into a single
    fluent sentence. All triples are combined; each predicate is expressed with a
    suitable phrase.
    """
    if not triples:
        return ""

    # Group triples by subject to handle related entities
    subject_triples: dict[str, list[Triple]] = {}
    for triple in triples:
        if triple.subject not in subject_triples:
            subject_triples[triple.subject] = []
        subject_triples[triple.subject].append(triple)

    # Find the monument as the main subject
    main_subject = None
    for subj in subject_triples.keys():
        if "Monument" in subj or "Memorial" in subj or "Plack" in subj:
            main_subject = subj
            break
    if main_subject is None:
        main_subject = triples[0].subject

    # Collect all information for the main subject
    location_info: list[str] = []
    attributes: list[str] = []
    related_entities: dict[str, dict] = {}  # Track related entities and their info

    for subject, sub_triples in subject_triples.items():
        for triple in sub_triples:
            p = triple.predicate
            o = triple.object.strip('"')

            if subject == main_subject:
                # Handle location hierarchy
                if p == "location":
                    location_info.append(("location", o))
                elif p == "municipality":
                    location_info.append(("municipality", o))
                elif p == "state":
                    location_info.append(("state", o))
                elif p == "country":
                    location_info.append(("country", o))
                elif p == "district":
                    location_info.append(("district", o))
                # Handle other attributes
                elif p == "category":
                    attributes.append(f"is a {o}")
                elif p in ("established", "foundingDate"):
                    attributes.append(f"was established in {o}")
                elif p == "inaugurationDate":
                    attributes.append(f"was inaugurated on {o}")
                elif p in ("owner", "owningOrganisation"):
                    attributes.append(f"is owned by {o}")
                elif p == "dedicatedTo":
                    attributes.append(f"is dedicated to {o}")
                elif p == "designer":
                    attributes.append(f"was designed by {o}")
                elif p == "material":
                    attributes.append(f"is made of {o}")
                elif p == "nativeName":
                    attributes.append(f'with native name "{o}"')
                elif p == "nearestCity":
                    attributes.append(f"nearest city is {o}")
                elif p == "ethnicGroup":
                    attributes.append(f"associated with the {o}")
                elif p == "language":
                    attributes.append(f"language is {o}")
                elif p == "religion":
                    attributes.append(f"religion is {o}")
            else:
                # Track related entity information
                if subject not in related_entities:
                    related_entities[subject] = {}
                related_entities[subject][p] = o

    # Build location phrase
    location_phrase = ""
    if location_info:
        loc_parts = []
        country = None
        state = None
        district = None
        municipality = None
        location = None

        for loc_type, value in location_info:
            if loc_type == "country":
                country = value
            elif loc_type == "state":
                state = value
            elif loc_type == "district":
                district = value
            elif loc_type == "municipality":
                municipality = value
            elif loc_type == "location":
                location = value

        # Build location hierarchy - only add non-empty parts, more natural phrasing
        if district:
            loc_parts.append(f"the district of {district}")
        if location:
            loc_parts.append(location)
        if municipality:
            loc_parts.append(municipality)
        if state:
            loc_parts.append(state)
        if country:
            loc_parts.append(country)

        if loc_parts:
            # Create natural location string (e.g., "Gettysburg, Pennsylvania")
            loc_str = ", ".join(loc_parts)
            location_phrase = f"located in {loc_str}"
        else:
            # Only use if we have actual location values
            loc_values = [v for _, v in location_info if v]
            if loc_values:
                location_phrase = "located in " + ", ".join(loc_values)

    # Build related entity phrases (country info, etc.) - integrate into main sentence
    related_info = ""
    for entity, info in related_entities.items():
        parts = []
        if "capital" in info:
            parts.append(f"the capital is {info['capital']}")
        if "leader" in info:
            parts.append(f"the leader is {info['leader']}")
        if "leaderTitle" in info:
            parts.append(f"the {info['leaderTitle']}")
        if "legislature" in info:
            parts.append(f"the legislature is {info['legislature']}")
        if "currency" in info:
            parts.append(f"the currency is {info['currency']}")
        if "largestCity" in info:
            parts.append(f"the largest city is {info['largestCity']}")

        if parts:
            related_info = f", {entity}, where " + "; ".join(parts)
            break  # Only use one related entity for now

    # Build the final sentence - construct more naturally as one complex sentence
    sentence_parts = [main_subject]

    # Add location phrase if exists
    if location_phrase:
        sentence_parts.append(location_phrase)

    # Add attributes if exist
    if attributes:
        attr_str = "; ".join(attributes)
        sentence_parts.append(f" and {attr_str}")

    # Add related entity info if exists
    if related_info:
        sentence_parts.append(related_info)

    # Join all parts with proper comma handling - filter out empty strings
    sentence_parts = [p for p in sentence_parts if p and p.strip()]

    if len(sentence_parts) > 1:
        sentence = ", ".join(sentence_parts) + "."
    elif sentence_parts:
        sentence = sentence_parts[0] + "."
    else:
        sentence = main_subject + "."

    return sentence

